function buildPyramid(n) {
    if (n <= 0) return '';
    let result = '';
    for (let i = 1; i <= n; i++) {
        result += ' '.repeat(n - i) + '#'.repeat(2 * i - 1);
        if (i < n) result += '\n';
    }
    return result;
}

function drawTree(height) {
    if (height <= 0) return '';

    let result = '';

    // Ярусы: для каждого i от 1 до height — пирамида высотой i + 1
    for (let i = 1; i <= height; i++) {
        result += buildPyramid(i + 1);
        result += '\n';
    }

    // Ствол: одна # по центру последнего (самого широкого) яруса
    // Ширина последнего яруса: 2 * (height + 1) - 1 = 2*height + 1
    let stemWidth = 2 * height + 1;
    let stemSpaces = Math.floor(stemWidth / 2);
    if (stemSpaces > 0) {
        result += ' '.repeat(stemSpaces) + '#';
    } else {
        result += '#';
    }

    return result;
}

